4	/**
5	 * Document-level macro (holistic layer) health, surfaced in Admin -> Documents so
6	 * a document whose macro layer failed can never read as a green `complete`.
7	 *
8	 * Precedence (worst wins, race-tolerant so the fire-and-forget followups can
9	 * finish in any order): failed > degraded > complete > pending > not_applicable.
10	 *
11	 *   - markMacroPending  — set when document-ingestion dispatches the outline (fresh run).
12	 *   - markMacroComplete — a followup succeeded and nothing has failed yet.
13	 *   - markMacroDegraded — a macro/coverage followup failed (partial holistic layer).
14	 *   - markMacroFailed   — the outline itself failed (no holistic layer at all).
15	 *
16	 * The conditional WHERE clauses make these safe to call concurrently: a success
17	 * can never overwrite a recorded failure, and a failure always downgrades.
18	 */
19	export type MacroHealth = 'not_applicable' | 'pending' | 'complete' | 'degraded' | 'failed';
20	
21	async function setMacroHealth(
22	  db: OracleDb,
23	  documentId: string | null | undefined,
24	  value: MacroHealth,
25	  onlyWhenIn?: MacroHealth[],
26	): Promise<void> {
27	  if (!documentId) return;
28	  const guard = onlyWhenIn?.length
29	    ? sql` AND macro_health IN (${sql.join(
30	        onlyWhenIn.map((v) => sql`${v}`),
31	        sql`, `,
32	      )})`
33	    : sql``;
34	  try {
35	    await db.execute(sql`
36	      UPDATE documents
37	      SET macro_health = ${value}
38	      WHERE id = ${documentId}::uuid${guard}
39	    `);
40	  } catch (err) {
41	    // Health is observability, never load-bearing — a failed health write must
42	    // not mask or replace the real worker outcome.
43	    console.warn('[macro-health] failed to set', { documentId, value, err });
44	  }
45	}
46	
47	export function markMacroPending(db: OracleDb, documentId?: string | null): Promise<void> {
48	  return setMacroHealth(db, documentId, 'pending');
49	}
50	
51	export function markMacroComplete(db: OracleDb, documentId?: string | null): Promise<void> {
52	  // Only promote to complete if nothing has failed/degraded this run.
53	  return setMacroHealth(db, documentId, 'complete', ['pending']);
54	}
55	
56	export function markMacroDegraded(db: OracleDb, documentId?: string | null): Promise<void> {
57	  // Downgrade from pending/complete; never overwrite a hard 'failed'.
58	  return setMacroHealth(db, documentId, 'degraded', ['pending', 'complete']);
59	}
60	
61	export function markMacroFailed(db: OracleDb, documentId?: string | null): Promise<void> {
62	  return setMacroHealth(db, documentId, 'failed');
63	}
