574	  let payloadDocId: string | null = null;
575	  try {
576	    payloadDocId = payloadSchema.parse(rawPayload).documentId ?? null;
577	  } catch {
578	    payloadDocId = null;
579	  }
580	  const [jobRun] = await db
581	    .insert(jobRuns)
582	    .values({
583	      triggerRunId,
584	      jobType: 'macro-relationship-extraction',
